import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI, Type } from "@google/genai";
import dotenv from "dotenv";

dotenv.config();

const app = express();
app.use(express.json({ limit: "15mb" }));

// Initialize Google Gen AI helper with per-request support
function getAISDK(req: express.Request) {
  const clientKey = req.headers["x-api-key"] as string;
  const key = clientKey || process.env.GEMINI_API_KEY;
  if (!key) {
    throw new Error("Chave de API do Gemini não configurada. Por favor, adicione sua chave de API nas configurações ou use a do servidor.");
  }
  return new GoogleGenAI({
    apiKey: key,
    httpOptions: {
      headers: {
        "User-Agent": "aistudio-build",
      },
    },
  });
}

// API: Validate custom client API key
app.post("/api/validate-key", async (req, res) => {
  try {
    const key = req.headers["x-api-key"] as string || req.body.key;
    if (!key) {
      return res.status(400).json({ success: false, error: "Chave não fornecida." });
    }
    const testAi = new GoogleGenAI({
      apiKey: key,
      httpOptions: {
        headers: { "User-Agent": "aistudio-build" }
      }
    });
    // Test call with minimal token count
    await testAi.models.generateContent({
      model: "gemini-3.5-flash",
      contents: "Respond only with 'OK'",
    });
    res.json({ success: true });
  } catch (err: any) {
    console.error("Validation error:", err);
    res.json({ success: false, error: err.message || "Chave inválida ou erro na API." });
  }
});

// Response Schema for Diagram Data
const diagramSchema = {
  type: Type.OBJECT,
  properties: {
    title: { type: Type.STRING },
    type: { type: Type.STRING, description: "Must be: flowchart, bpmn, uml, er, or mindmap" },
    nodes: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          type: { type: Type.STRING, description: "e.g., task, gateway, event, class, entity, attribute, relationship, start, end, mindmap-node" },
          label: { type: Type.STRING },
          x: { type: Type.NUMBER },
          y: { type: Type.NUMBER },
          shape: { type: Type.STRING, description: "rectangle, diamond, circle, ellipse, pill, parallelogram, class-box" },
          color: { type: Type.STRING, description: "E.g. #3b82f6, #ef4444, #10b981, #f59e0b, #8b5cf6, #ec4899" },
          properties: {
            type: Type.ARRAY,
            items: { type: Type.STRING },
            description: "For UML classes (attributes, methods) or database columns/types. Empty if none."
          }
        },
        required: ["id", "type", "label", "x", "y", "shape", "color"]
      }
    },
    edges: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          from: { type: Type.STRING },
          to: { type: Type.STRING },
          label: { type: Type.STRING },
          type: { type: Type.STRING, description: "flow, association, inheritance, dependency, relation" },
          cardinality: { type: Type.STRING, description: "e.g. 1..N, 1..1, N..M (for ER)" },
          animated: { type: Type.BOOLEAN }
        },
        required: ["id", "from", "to"]
      }
    },
    mermaid: { type: Type.STRING, description: "Proper, compilable Mermaid.js markdown block code" },
    d2: { type: Type.STRING, description: "Proper, readable D2 diagram declarative script" },
    markdown: { type: Type.STRING, description: "Detailed Markdown guide/documentation structured for Notion or Obsidian including layout explanation" },
    htmlSystem: { type: Type.STRING, description: "A beautiful, fully self-contained HTML (using Tailwind CSS CDN) with embedded Javascript and state, making a functional, highly-polished direct interactive playground simulation or mock application representing the system represented by this diagram." }
  },
  required: ["title", "type", "nodes", "edges", "mermaid", "d2", "markdown", "htmlSystem"]
};

const SYSTEM_INSTRUCTIONS = `You are a world-class system architect and diagram generation specialist. 
Your goal is to parse text prompts, uploaded source codes, markdown, BPMN XML, ER representations, D2 syntax, or mind maps, and outputs a complete, organized, animated diagram model in JSON along with a fully functioning mock-application prototype system.

Design exquisite diagrams with clear relative 2D positions (x, y coordinates ranging naturally from 100 to 1000, spacing them out proportionally so nodes do NOT overlap or crowd each other).
Choose aesthetically professional color schemes based on diagram category.
For the 'htmlSystem':
- It must be a fully responsive, visually stunner, single-page web application using:
  - Tailwind CSS (via CDN: https://cdn.tailwindcss.com)
  - Beautiful typographic layouts, spacing, shadows, microinteractions, tabs (if needed), input fields, action buttons, table records, stored locally using standard state or localStorage.
  - It MUST functionally emulate/mock the actual business processes, forms, calculations, or models described by the diagram. For example, if it's a BPMN authorization process, write a multi-step form with mock notifications, interactive logs, success dashboard, and user configurations. Keep it highly interactive, visually polished and realistic.
  - Deliver pristine code without any truncated lines. Do not truncate! All HTML must be fully complete and operational.

Format all responses matching the schema exactly. Choose the most appropriate diagram type (flowchart, bpmn, uml, er, mindmap) representing the user prompt if not explicitly specified.`;

// API: Generate diagram from prompt / files
app.post("/api/generate-diagram", async (req, res) => {
  try {
    const { prompt, diagramType, fileContent, fileName, fileExt } = req.body;
    const ai = getAISDK(req);

    let userPrompt = `Generate a diagram of type: ${diagramType || "auto-detect"}.\n`;
    if (prompt) {
      userPrompt += `User request: "${prompt}"\n`;
    }
    if (fileContent) {
      userPrompt += `Uploaded context file "${fileName || "diagram-file"}" with extension "${fileExt || "txt"}":\n-----------\n${fileContent}\n-----------\n`;
    }

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS,
        responseMimeType: "application/json",
        responseSchema: diagramSchema,
        temperature: 0.2,
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response or empty text from Gemini API.");
    }

    const cleanedJson = JSON.parse(outputText.trim());
    res.json({ success: true, diagram: cleanedJson });
  } catch (error: any) {
    console.error("Error generating diagram:", error);
    res.status(500).json({ success: false, error: error.message || error });
  }
});

// API: Refactor diagram
app.post("/api/refactor-diagram", async (req, res) => {
  try {
    const { diagram, refinementPrompt } = req.body;
    const ai = getAISDK(req);

    if (!diagram || !refinementPrompt) {
      return res.status(400).json({ success: false, error: "diagram and refinementPrompt are required." });
    }

    const userPrompt = `Refactor and modify the following diagram metadata based on user feedback.\n` +
      `Feedback: "${refinementPrompt}"\n` +
      `Current diagram state:\n-----------\n${JSON.stringify(diagram, null, 2)}\n-----------\n` +
      `Please reconstruct the entire model, updating coordinates, shapes, colors, mermaid code, d2 code, markdown and rebuilding/improving the htmlSystem mock application accordingly. Expand coordinates naturally if new nodes are added. Maintain overall style cohesion.`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS,
        responseMimeType: "application/json",
        responseSchema: diagramSchema,
        temperature: 0.2,
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response or empty text from Gemini API.");
    }

    const cleanedJson = JSON.parse(outputText.trim());
    res.json({ success: true, diagram: cleanedJson });
  } catch (error: any) {
    console.error("Error refactoring diagram:", error);
    res.status(500).json({ success: false, error: error.message || error });
  }
});

// API: Quick rebuild of htmlSystem only
app.post("/api/regenerate-system", async (req, res) => {
  try {
    const { diagram, customizationRequest } = req.body;
    const ai = getAISDK(req);

    if (!diagram) {
      return res.status(400).json({ success: false, error: "diagram data is required." });
    }

    const userPrompt = `Review the following diagram layout and build/rebuild the 'htmlSystem' mockup system.\n` +
      `Diagram details:\n${JSON.stringify({ title: diagram.title, type: diagram.type, nodes: diagram.nodes, edges: diagram.edges }, null, 2)}\n` +
      `Customization request: "${customizationRequest || "Build a fully integrated prototype based exactly on this system model with state persistence, interactive fields and clean logging."}"\n` +
      `Return a single JSON block containing ONLY a single key 'htmlSystem' which contains the complete, standalone HTML string representing this system mockup. Ready to run and fully styled!`;

    const response = await ai.models.generateContent({
      model: "gemini-3.5-flash",
      contents: userPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTIONS,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            htmlSystem: { type: Type.STRING }
          },
          required: ["htmlSystem"]
        },
        temperature: 0.2,
      },
    });

    const outputText = response.text;
    if (!outputText) {
      throw new Error("No response from Gemini API.");
    }

    const cleanedJson = JSON.parse(outputText.trim());
    res.json({ success: true, htmlSystem: cleanedJson.htmlSystem });
  } catch (error: any) {
    console.error("Error regenerating HTML system:", error);
    res.status(500).json({ success: false, error: error.message || error });
  }
});

// Serve frontend with Vite in development, static files in production
async function startServer() {
  const PORT = 3000;

  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`[DEVELOPMENT SERVER] running on http://localhost:${PORT}`);
  });
}

startServer();
